const list = document.querySelector('ul')

for (let i = 0; i < 100; i++) {
  const li = document.createElement('li')
  li.textContent = `Элемент ${i}`
  list.appendChild(li)  // ← 100 reflow!
}

const fragment = document.createDocumentFragment()
// fragment — не часть DOM, изменения в нём
// не вызывают reflow

const fragment = document.createDocumentFragment()

for (let i = 0; i < 100; i++) {
  const li = document.createElement('li')
  li.textContent = `Элемент ${i}`
  fragment.appendChild(li)  // ← 0 reflow!
}

const list = document.querySelector('ul')
list.appendChild(fragment)  // ← 1 reflow!
// Все 100 элементов вставлены за одну операцию
// fragment теперь пустой (все дети перемещены в list)
